mapper.select:
SELECT
	a.homepage_id, a.manage_idx, b.board_name, a.subject, a.remark,
	a.yearmonth, a.add_date, a.add_id, a.modify_date, a.modify_id, a.category1
FROM
	THEME_BOOK a, CMS_BOARD_MANAGE b
WHERE
	a.homepage_id = #{homepage_id}
AND	a.manage_idx = #{manage_idx}
AND	a.manage_idx = b.manage_idx
AND	yearmonth = #{yearmonth}
AND	a.category1 = #{category1}

