	THEME_BOOK
(
	homepage_id, manage_idx, yearmonth, subject, remark,
	add_date, add_id, modify_date, modify_id, category1
) VALUES
( 
	#{homepage_id}, #{manage_idx}, #{yearmonth}, #{subject}, #{remark},
	SYSDATE, #{cud_id}, SYSDATE, #{cud_id}, #{category1}
)

mapper.update:
UPDATE
	THEME_BOOK
SET
	subject = #{subject},
	remark = #{remark},
	modify_date = SYSDATE,
	modify_id = #{cud_id}
WHERE
	homepage_id = #{homepage_id} 
AND	manage_idx = #{manage_idx}
AND	yearmonth = #{yearmonth}
AND	category1 = #{category1}

